-- Luke Chapter 17
-- Theme: Faith, Gratitude, and the Unexpected Coming of the Son of Man
-- 37 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 17,
  'Luke 17 falls into two distinct halves: a series of discipleship sayings (vv.1-19) and an extended eschatological discourse (vv.20-37). The discipleship sayings address four interconnected themes: the gravity of causing another to stumble (vv.1-2), the obligation of repeated forgiveness (vv.3-4), the nature of faith (vv.5-6), and the proper posture of service (vv.7-10). Together they form a catechesis for community life in the kingdom, focusing on the disciple''s responsibilities toward fellow believers and toward God.',
  'The healing of the ten lepers (vv.11-19) is one of Luke''s most distinctive narratives. Ten men cry from a distance for mercy; Jesus sends them to the priests while they are still unclean — testing their faith. All ten are cleansed on the way, but only one returns to give thanks, and he is a Samaritan. Jesus''s question — "Were there not ten cleansed? but where are the nine?" — is one of the most poignant in the Gospels. The Samaritan''s faith and gratitude are linked to salvation (v.19: "thy faith hath made thee whole") in a way the other nine''s physical healing was not.',
  'The eschatological discourse (vv.20-37) begins with a Pharisaic question about when the kingdom comes. Jesus corrects the premise: the kingdom does not come "with observation" (meta paratērēseōs — with signs to be watched for); it is already "within you" or "among you" (entos humōn — in your midst). He then shifts to address the disciples about the final coming of the Son of Man: first a period of suffering and apparent defeat (v.25), then a sudden, unmistakable appearing like lightning (v.24).',
  'The days of Noah and Lot provide the typological framework: ordinary life continues until sudden catastrophic judgment falls, with no warning for those not watching. "Remember Lot''s wife" (v.32) — the backward glance that cost her life — is the warning against clinging to the present age when the Son of Man comes. The paradoxes of saving and losing life (v.33) and the selective taking at night (vv.34-35) emphasize that the coming will make sudden, irreversible separations. The eagles gathered around the carcass (v.37) is a proverbial saying about the location of judgment — where the dead body is, there the vultures gather.',
  'πίστις (pistis)',
  'pistis means faith, trust, reliance, confidence in God''s word and character. In Luke 17, it appears in the disciples'' request — "Lord, increase our faith" (v.5: prosthes hēmin pistin) — and in Jesus''s response about the mustard-seed faith that can transplant trees (v.6). It reappears at the chapter''s narrative center in Jesus''s word to the grateful leper: "thy faith hath made thee whole" (hē pistis sou sesōken se, v.19). The juxtaposition of small-faith sayings (vv.5-6) with the Samaritan''s whole-making faith (v.19) reveals that faith is not measured by quantity but by orientation toward the person of Jesus.',
  '["Discipleship in Community: Stumbling, Forgiveness, Faith, and Service (vv.1-10)","The Ten Lepers: Cleansing, Gratitude, and Wholeness (vv.11-19)","The Kingdom''s Nature and Presence (vv.20-21)","The Day of the Son of Man: Sudden, Unmistakable, and Selective (vv.22-37)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Then said he unto the disciples, It is impossible but that offences will come: but woe unto him, through whom they come!', 'Εἶπεν δὲ πρὸς τοὺς μαθητάς, Ἀνένδεκτόν ἐστιν τοῦ τὰ σκάνδαλα μὴ ἐλθεῖν· πλὴν οὐαὶ δι'' οὗ ἔρχεται·', 'Eipen de pros tous mathētas, AnEndekton estin tou ta skandala mē elthein; plēn ouai di'' hou erchetai;', '"It is impossible" (AnEndekton — inadmissible, unthinkable, not allowable, a rare word used only here in the NT) that offences (skandala — stumbling blocks, traps, snares) will not come — fallen humanity guarantees their arrival. "But woe" (plēn ouai — nevertheless, woe) to the individual through whom they come. The inevitability of temptation does not diminish individual culpability. The universal reality of sin''s presence does not excuse the personal responsibility of those who introduce it.', NULL),
  (2, 'It were better for him that a millstone were hanged about his neck, and he cast into the sea, than that he should offend one of these little ones.', 'λυσιτελεῖ αὐτῷ εἰ λίθος μυλικὸς περίκειται περὶ τὸν τράχηλον αὐτοῦ καὶ ἔρριπται εἰς τὴν θάλασσαν, ἢ ἵνα σκανδαλίσῃ τῶν μικρῶν τούτων ἕνα.', 'lusitelei autō ei lithos mulikos perikeitai peri ton trachēlon autou kai erriptai eis tēn thalassan, ē hina skandalisē tōn mikrōn toutōn hena.', '"It were better" (lusitelei — it profits more, it is more advantageous) — a striking commercial metaphor: being drowned in the sea with a millstone is a better deal than the eschatological cost of causing a little one to stumble. "A millstone" (lithos mulikos — a large grinding stone, turned by a donkey) was massive — certainly lethal if used as a necklace in water. "Little ones" (mikrōn) — probably new or weak believers, the spiritually vulnerable within the community. Their protection is a primary community obligation.', NULL),
  (3, 'Take heed to yourselves: If thy brother trespass against thee, rebuke him; and if he repent, forgive him.', 'προσέχετε ἑαυτοῖς. ἐὰν ἁμάρτῃ ὁ ἀδελφός σου, ἐπιτίμησον αὐτῷ, καὶ ἐὰν μετανοήσῃ, ἄφες αὐτῷ.', 'prosechete heautois. ean hamartē ho adelphos sou, epitimēson autō, kai ean metanoēsē, aphes autō.', '"Take heed to yourselves" (prosechete heautois — watch out for yourselves, pay attention to your own souls) before attending to the brother. "Rebuke him" (epitimēson — rebuke, admonish, correct; the word used for rebuking demons and storms) — the rebuke is an act of love, not condemnation. "If he repent" (ean metanoEsē — if he changes his mind and direction) "forgive him" (aphes autō — release him, grant forgiveness). The conditional "if he repent" qualifies the forgiveness — forgiveness requires repentance, unlike God''s prevenient grace.', NULL),
  (4, 'And if he trespass against thee seven times in a day, and seven times in a day turn again to thee, saying, I repent; thou shalt forgive him.', 'καὶ ἐὰν ἑπτάκις τῆς ἡμέρας ἁμαρτήσῃ εἰς σέ, καὶ ἑπτάκις ἐπιστρέψῃ πρὸς σέ, λέγων, Μετανοῶ, ἀφήσεις αὐτῷ.', 'kai ean heptakis tēs hēmeras hamartēsē eis se, kai heptakis epistrepsē pros se, legōn, Metanoō, aphēseis autō.', '"Seven times in a day" — a number of completeness emphasizing an extreme case. Each time the brother turns (epistrepsē — returns, reverses direction) and says "I repent" (Metanoō — I am repenting, present tense), "thou shalt forgive him" (aphēseis — you will release, future tense as a command). The forgiveness is not for the unrepentant but matches each act of repentance. The demand is severe: seven offenses, seven returns, seven forgivenesses — all in one day. This is the economy of the kingdom, not natural human patience.', NULL),
  (5, 'And the apostles said unto the Lord, Lord, increase our faith.', 'Καὶ εἶπαν οἱ ἀπόστολοι τῷ Κυρίῳ, Πρόσθες ἡμῖν πίστιν.', 'Kai eipan hoi apostoloi tō Kuriō, Prosthes hēmin pistin.', 'The apostles'' response to the demands of vv.1-4 is a prayer for more faith — they feel inadequate for what has just been required. "Increase our faith" (Prosthes hēmin pistin — add to us faith, give us more faith, prosthes is the aorist imperative of prostithēmi — to add to). The request implies they have some faith but feel it insufficient for the demands of community forgiveness and the avoidance of causing stumbling. Jesus''s answer will reframe the question: it is not about the quantity of faith but about the object.', NULL),
  (6, 'And the Lord said, If ye had faith as a grain of mustard seed, ye might say unto this sycamine tree, Be thou plucked up by the root, and be thou planted in the sea; and it should obey you.', 'εἶπεν δὲ ὁ Κύριος, Εἰ ἔχετε πίστιν ὡς κόκκον σινάπεως, ἐλέγετε ἂν τῇ συκαμίνῳ ταύτῃ, Ἐκριζώθητι καὶ φυτεύθητι ἐν τῇ θαλάσσῃ· καὶ ὑπήκουσεν ἂν ὑμῖν.', 'eipen de ho Kurios, Ei echete pistin hōs kokkon sinapeōs, elegete an tē sukaminō tautē, Ekrizōthēti kai phutEuthēti en tē thalassē; kai hupēkousen an humin.', '"A grain of mustard seed" — the proverbially smallest seed represents genuine (even tiny) faith. The "sycamine tree" (sukaminō — the black mulberry tree, noted for its extremely deep, extensive root system, the most difficult tree to uproot) would obey even the smallest real faith. The point is not arithmetic — more faith moves bigger trees — but that the disciples already have sufficient faith. The problem is not the quantity of their faith but their failure to exercise what they have. True faith, however small, accomplishes what God has willed.', NULL),
  (7, 'But which of you, having a servant plowing or feeding cattle, will say unto him by and by, when he is come from the field, Go and sit down to meat?', 'Τίς δὲ ἐξ ὑμῶν δοῦλον ἔχων ἀροτριῶντα ἢ ποιμαίνοντα, ὃς εἰσελθόντι ἐκ τοῦ ἀγροῦ ἐρεῖ αὐτῷ, Εὐθέως παρελθὼν ἀνάπεσε;', 'Tis de ex humōn doulon echōn arotriōnta ē poimainonta, hos eiselthonti ek tou agrou erei autō, Eutheōs parelthōn anapese?', 'A new parable addressing the disciples'' self-congratulatory attitudes after obedient service. The rhetorical question (Tis ex humōn — which of you) expects the answer "no one" — no master immediately rewards a returning field slave with dinner. "Go and sit down to meat" (parelthōn anapese — come in and recline, take your place as a guest) would be absurd before the master''s own needs are met. The parable establishes that discipleship obligations are not fulfilled by one''s own satisfaction but by the master''s.', NULL),
  (8, 'And will not rather say unto him, Make ready wherewith I may sup, and gird thyself, and serve me, till I have eaten and drunken; and afterward thou shalt eat and drink?', 'ἀλλ'' οὐχὶ ἐρεῖ αὐτῷ, Ἑτοίμασον τί δειπνήσω, καὶ περιζωσάμενος διακόνει μοι ἕως φάγω καὶ πίω, καὶ μετὰ ταῦτα φάγεσαι καὶ πίεσαι σύ;', 'all'' ouchi erei autō, Hetoimason ti deipnēsō, kai perizōsamenos diakonei moi heōs phagō kai piō, kai meta tauta phagesai kai piesai su?', '"Gird thyself, and serve me" (perizōsamenos diakonei moi — put on your apron and wait on me, serve as a table servant) — the servant''s work does not end when the field work ends; it transitions from one form of service to another. "Afterward thou shalt eat and drink" — the servant''s own satisfaction comes after the master''s. Jesus himself modeled this at the Last Supper (22:27: "I am among you as he that serveth"), but the pattern is established here as the norm for kingdom service.', NULL),
  (9, 'Doth he thank that servant because he did the things that were commanded him? I trow not.', 'μὴ ἔχει χάριν τῷ δούλῳ ἐκείνῳ ὅτι ἐποίησεν τὰ διαταχθέντα; οὐ δοκῶ.', 'mē echei charin tō doulō ekeinō hoti epoiEsen ta diatachthenta; ou dokō.', '"Doth he thank that servant" (mē echei charin — does he have grace/gratitude for that slave, does he owe him thanks?) — the expected answer is "no." A slave who does what is commanded earns no special gratitude; he has merely fulfilled his obligation. "I trow not" (ou dokō — I think not) — a colloquial Lucan aside. The point: obedient disciples should not expect special commendation for fulfilling basic duties. The mentality of merit and reward is inappropriate for those who understand their servant status.', NULL),
  (10, 'So likewise ye, when ye shall have done all those things which are commanded you, say, We are unprofitable servants: we have done that which was our duty to do.', 'οὕτως καὶ ὑμεῖς, ὅταν ποιήσητε πάντα τὰ διαταχθέντα ὑμῖν, λέγετε ὅτι Δοῦλοι ἀχρεῖοί ἐσμεν, ὅτι ὃ ὠφείλομεν ποιῆσαι πεποιήκαμεν.', 'houtōs kai humeis, hotan poiēsēte panta ta diatachthenta humin, legete hoti Douloi achreIoi esmen, hoti ho ōpheilomen poiēsai pepoiēkamen.', '"Unprofitable servants" (douloi achreIoi — useless slaves, literally: without benefit or advantage) — not a word of self-condemnation but of realistic assessment: we have not put God in our debt. "We have done that which was our duty to do" (ho ōpheilomen poiēsai pepoiēkamen — what we were obligated to do we have done). All obedience is the fulfillment of pre-existing obligation; it creates no surplus credit account with God. This statement guards against the Pharisaic assumption that accumulated good deeds merit divine reward.', NULL),
  (11, 'And it came to pass, as he went to Jerusalem, that he passed through the midst of Samaria and Galilee.', 'Καὶ ἐγένετο ἐν τῷ πορεύεσθαι εἰς Ἰερουσαλήμ, καὶ αὐτὸς διήρχετο διὰ μέσον Σαμαρείας καὶ Γαλιλαίας.', 'Kai egeneto en tō poreuesthai eis Ierousalēm, kai autos diērcheto dia meson Samareias kai Galilaias.', 'A geographical transition reminder (cf. 9:51; 13:22): the journey to Jerusalem continues. "Through the midst of Samaria and Galilee" — the border region between the two territories, a liminal zone where social categories blurred. The setting is precisely where Jews and Samaritans lived in closest proximity and deepest tension — the ideal setting for a story about a Samaritan''s exemplary response that would challenge Jewish assumptions about insiders and outsiders.', NULL),
  (12, 'And as he entered into a certain village, there met him ten men that were lepers, which stood afar off:', 'καὶ εἰσερχομένου αὐτοῦ εἴς τινα κώμην, ἀπήντησαν αὐτῷ δέκα λεπροὶ ἄνδρες, οἳ ἔστησαν πόρρωθεν,', 'kai eiserchomEnou autou eis tina kōmēn, apēntēsan autō deka leproi andres, hoi estēsan porrōthen,', '"Ten lepers" (deka leproi) — a group, mixed in ethnicity (one Samaritan, presumably nine Jews), united by their common outcaste status. Leprosy (a general term for various skin diseases) required social isolation under the Law (Lev 13:45-46). "Stood afar off" (estēsan porrōthen — stood at a distance, as the Law required) — maintaining the prescribed separation even in their desperate appeal. The group''s shared suffering created a community across ethnic lines that would not have existed under normal social conditions.', NULL),
  (13, 'And they lifted up their voices, and said, Jesus, Master, have mercy on us.', 'καὶ αὐτοὶ ἦραν φωνὴν λέγοντες, Ἰησοῦ ἐπιστάτα, ἐλέησον ἡμᾶς.', 'kai autoi ēran phōnēn legontes, Iēsou epistata, eleēson hēmas.', '"Master" (epistata — superintendent, overseer; Luke''s equivalent of Mark''s Rabbi, used by the disciples) — a title of authority and respect. "Have mercy on us" (eleēson hēmas — the mercy-cry, used also by the blind beggar in 18:38-39) — they appeal not to merit but to mercy. The plural "us" — the group appeals together, perhaps the only time a group of people so diverse in ethnicity prayed together. Their shared helplessness produces common prayer, a pattern that transcends social divisions.', NULL),
  (14, 'And when he saw them, he said unto them, Go shew yourselves unto the priests. And it came to pass, that, as they went, they were cleansed.', 'καὶ ἰδὼν εἶπεν αὐτοῖς, Πορευθέντες ἐπιδείξατε ἑαυτοὺς τοῖς ἱερεῦσιν. καὶ ἐγένετο ἐν τῷ ὑπάγειν αὐτοὺς ἐκαθαρίσθησαν.', 'kai idōn eipen autois, Poreuthentes epideixate heautous tois hiereusin. kai egeneto en tō hupagein autous ekatharisthēsan.', '"Go shew yourselves unto the priests" (epideixate heautous tois hiereusin) — the priestly examination was the required certification of cleansing (Lev 14:1-32). They are sent while still unclean — an act of faith required before the healing is visible. "As they went, they were cleansed" (en tō hupagein autous ekatharisthēsan — while they were going, in the process of obeying, they were cleansed) — obedient movement in faith preceded visible cleansing. This is a pattern of Lucan faith: response to the word before the evidence arrives.', NULL),
  (15, 'And one of them, when he saw that he was healed, turned back, and with a loud voice glorified God,', 'εἷς δὲ ἐξ αὐτῶν, ἰδὼν ὅτι ἰάθη, ὑπέστρεψεν μετὰ φωνῆς μεγάλης δοξάζων τὸν Θεόν,', 'heis de ex autōn, idōn hoti iathē, hupestrepsen meta phōnēs megalēs doxazōn ton Theon,', '"One of them" (heis de ex autōn) — the singular standing out from the nine. "When he saw that he was healed" (idōn hoti iathē) — the recognition of healing precedes the return. "Turned back" (hupestrepsen — returned, reversed course) — against the direction of the priest-journey, choosing relationship over regulation, gratitude over procedure. "With a loud voice glorified God" (meta phōnēs megalēs doxazōn ton Theon) — the praise is public, vocal, unreserved. He does not go quietly back; he shouts his thanksgiving.', NULL),
  (16, 'And fell down on his face at his feet, giving him thanks: and he was a Samaritan.', 'καὶ ἔπεσεν ἐπὶ πρόσωπον παρὰ τοὺς πόδας αὐτοῦ εὐχαριστῶν αὐτῷ· καὶ αὐτὸς ἦν Σαμαρίτης.', 'kai epesen epi prosōpon para tous podas autou eucharistōn autō; kai autos ēn Samaritēs.', '"Fell down on his face" (epesen epi prosōpon — prostrated himself) — the posture of worship. "At his feet" (para tous podas autou) — the posture of ultimate reverence (cf. 7:38; 8:41; John 11:32). "Giving thanks" (eucharistōn — offering eucharist, thanksgiving, the root of the Eucharist). The identity is revealed last, for maximum narrative impact: "he was a Samaritan" (Samaritēs) — the theological outsider, the half-breed, the one who had the least reason (by Jewish reckoning) to come to Jesus''s feet.', NULL),
  (17, 'And Jesus answering said, Were there not ten cleansed? but where are the nine?', 'ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν, Οὐχὶ οἱ δέκα ἐκαθαρίσθησαν; οἱ δὲ ἐννέα ποῦ;', 'apokritheis de ho Iēsous eipen, Ouchi hoi deka ekatharisthēsan; hoi de ennea pou?', '"Were there not ten cleansed?" (Ouchi hoi deka ekatharisthēsan — were not the ten cleansed?) — the passive divine healing is affirmed. "But where are the nine?" (hoi de ennea pou) — one of the most poignant questions in the Gospels, expressing not merely the surprise at ingratitude but genuine grief over missed encounter. All ten were healed; only one returned to give thanks and receive the fullness of what healing could mean. The nine went on to their appointment with the priests, their religious duty, their restored social status — but not to Jesus.', NULL),
  (18, 'There are not found that returned to give glory to God, save this stranger.', 'οὐχ εὑρέθησαν ὑποστρέψαντες δοῦναι δόξαν τῷ Θεῷ εἰ μὴ ὁ ἀλλογενὴς οὗτος;', 'ouch heurethēsan hupostrepsantes dounai doxan tō Theō ei mē ho allogenēs houtos?', '"Not found" (ouch heurethēsan — they were not found, not discovered) — a passive suggesting Jesus was looking, expecting. "To give glory to God" (dounai doxan tō Theō) — the OT phrase for acknowledging God''s righteous action (Josh 7:19; John 9:24). "Save this stranger" (ei mē ho allogEnēs houtos — except this foreigner, this one of another race) — allogEnēs (from allos, other + genos, race/kind) is a stronger word than Samaritēs. The foreigner of another race gives glory to God while the covenant insiders proceed with their religious appointments.', NULL),
  (19, 'And he said unto him, Arise, go thy way: thy faith hath made thee whole.', 'καὶ εἶπεν αὐτῷ, Ἀναστὰς πορεύου· ἡ πίστις σου σέσωκέν σε.', 'kai eipen autō, Anastas poreuou; hē pistis sou sesōken se.', '"Thy faith hath made thee whole" (hē pistis sou sesōken se — your faith has saved you, the perfect tense: has saved and the salvation stands). The same formula as 7:50 (the sinful woman) and 8:48 (the hemorrhaging woman). The nine received physical healing; the Samaritan receives something more — sōtēria, salvation, wholeness of the entire person. The word sōzō encompasses both healing and salvation. His return, prostration, and thanksgiving were not the means of salvation but the evidence that saving faith was present in him, unlike in the nine who were healed but not transformed.', NULL),
  (20, 'And when he was demanded of the Pharisees, when the kingdom of God should come, he answered them and said, The kingdom of God cometh not with observation:', 'Ἐπερωτηθεὶς δὲ ὑπὸ τῶν Φαρισαίων πότε ἔρχεται ἡ βασιλεία τοῦ Θεοῦ, ἀπεκρίθη αὐτοῖς καὶ εἶπεν, Οὐκ ἔρχεται ἡ βασιλεία τοῦ Θεοῦ μετὰ παρατηρήσεως,', 'Eperōtētheis de hupo tōn Pharisaiōn pote erchetai hē basileia tou Theou, apekrithē autois kai eipen, Ouk erchetai hē basileia tou Theou meta paratērēseōs,', '"Demanded" (eperōtētheis — was questioned, the passive suggests the Pharisees'' initiative) — a technical theological question about eschatological timing, perhaps designed to discredit Jesus if his answer conflicted with popular expectation. "Not with observation" (meta paratērēseōs — with careful watching for signs, with astronomical observation, with the scrutiny of those searching for visible portents) — the kingdom does not arrive as a visible, predictable, observable phenomenon that can be tracked.', NULL),
  (21, 'Neither shall they say, Lo here! or, lo there! for, behold, the kingdom of God is within you.', 'οὐδὲ ἐροῦσιν, Ἰδοὺ ὧδε ἤ, Ἐκεῖ ἰδού· ἰδοὺ γὰρ ἡ βασιλεία τοῦ Θεοῦ ἐντὸς ὑμῶν ἐστιν.', 'oude erousin, Idou hōde ē, Ekei idou; idou gar hē basileia tou Theou entos humōn estin.', '"Within you" or "in your midst" (entos humōn — entos can mean either "inside" as an interior location or "in your midst" as a present, tangible reality among people). Given the Pharisaic audience, "in your midst" (among you) is more likely — Jesus himself is the kingdom''s embodiment standing in their presence. The kingdom is not coming at some distant future point to be tracked on a prophetic chart; it has already arrived in the person and ministry of Jesus, and they are failing to recognize it.', NULL),
  (22, 'And he said unto the disciples, The days will come, when ye shall desire to see one of the days of the Son of man, and ye shall not see it.', 'Εἶπεν δὲ πρὸς τοὺς μαθητάς, Ἐλεύσονται ἡμέραι ὅτε ἐπιθυμήσετε μίαν τῶν ἡμερῶν τοῦ Υἱοῦ τοῦ ἀνθρώπου ἰδεῖν, καὶ οὐκ ὄψεσθε.', 'Eipen de pros tous mathētas, Eleusontai hēmerai hote epithumēsete mian tōn hēmerōn tou Huiou tou anthrōpou idein, kai ouk opsesthe.', 'Jesus shifts from the Pharisees to the disciples — the eschatological discourse proper. "The days will come" — a transition to prophetic future. "Desire to see one of the days of the Son of man" — during the period of persecution and suffering that will follow Jesus''s departure, disciples will long for even one day of the kingdom''s visible manifestation (as during the Galilean ministry). "And ye shall not see it" — the era between Jesus''s ascension and return will be characterized by longing without fulfillment.', NULL),
  (23, 'And they shall say to you, See here; or, see there: go not after them, nor follow them.', 'καὶ ἐροῦσιν ὑμῖν, Ἰδοὺ ἐκεῖ, ἤ, Ἰδοὺ ὧδε· μὴ ἀπέλθητε μηδὲ διώξητε.', 'kai erousin humin, Idou ekei, ē, Idou hōde; mē apelthēte mēde diōxēte.', '"See here; or, see there" — false messiahs and apocalyptic enthusiasts who claim to know the location of the kingdom''s next manifestation. "Go not after them, nor follow them" (mē apelthēte mēde diōxēte — do not go away and do not pursue) — a double prohibition against following eschatological fads. The warning is prophylactic: the disciples will encounter many false "here is the kingdom" announcements and must resist the natural desire to follow any claim of special revelation about the time and place of the parousia.', NULL),
  (24, 'For as the lightning, that lighteneth out of the one part under heaven, shineth unto the other part under heaven; so shall also the Son of man be in his day.', 'ὥσπερ γὰρ ἡ ἀστραπὴ ἀστράπτουσα ἐκ τῆς ὑπ'' οὐρανὸν εἰς τὴν ὑπ'' οὐρανὸν λάμπει, οὕτως ἔσται ὁ Υἱὸς τοῦ ἀνθρώπου ἐν τῇ ἡμέρᾳ αὐτοῦ.', 'hōsper gar hē astrapē astraptOusa ek tēs hyp'' ouranon eis tēn hyp'' ouranon lampei, houtōs estai ho Huios tou anthrōpou en tē hēmera autou.', '"As the lightning" (hōsper gar hē astrapē — just as the lightning flash) — lightning cannot be missed, predicted, or located in advance; it simply blazes across the entire sky instantaneously. "From one part under heaven...unto the other" — hemisphere to hemisphere visibility, universal and unmistakable. The return of the Son of Man will be equally obvious: no one will need to be told "look here" or "look there" (v.23). Anyone who claims the kingdom has arrived secretly, in a hidden location, has already falsified it by that very claim.', NULL),
  (25, 'But first must he suffer many things, and be rejected of this generation.', 'πρῶτον δὲ δεῖ αὐτὸν πολλὰ παθεῖν καὶ ἀποδοκιμασθῆναι ἀπὸ τῆς γενεᾶς ταύτης.', 'prōton de dei auton polla pathein kai apodokimasthēnai apo tēs geneas tautēs.', '"First must he suffer" (prōton de dei auton polla pathein — first it is necessary for him to suffer many things) — the cross precedes the parousia. "Must" (dei — divine necessity, the same word used throughout Luke for Jesus''s redemptive destiny) — the suffering is not accidental but essential. "Rejected of this generation" (apodokimasthēnai — declared unfit after testing, as a stone rejected by builders, Ps 118:22) — the cross is not a deviation from the kingdom plan but the foundation of it.', NULL),
  (26, 'And as it was in the days of Noe, so shall it be also in the days of the Son of man.', 'καὶ καθὼς ἐγένετο ἐν ταῖς ἡμέραις Νῶε, οὕτως ἔσται καὶ ἐν ταῖς ἡμέραις τοῦ Υἱοῦ τοῦ ἀνθρώπου·', 'kai kathōs egeneto en tais hēmerais Nōe, houtōs estai kai en tais hēmerais tou Huiou tou anthrōpou;', '"As it was in the days of Noah" — the Flood typology for the parousia is drawn from Jewish apocalyptic tradition (1 Enoch 106-107) and Genesis 6-8. The analogy is not the wickedness of Noah''s day (though that existed) but the ordinariness of life up to the moment of judgment. People were eating, drinking, marrying — not necessarily sinful activities — but utterly unaware of the approaching catastrophe. The parousia will similarly interrupt normal life without gradual warning.', NULL),
  (27, 'They did eat, they drank, they married wives, they were given in marriage, until the day that Noe entered into the ark, and the flood came, and destroyed them all.', 'ἤσθιον, ἔπινον, ἐγάμουν, ἐγαμίζοντο, ἄχρι ἧς ἡμέρας εἰσῆλθεν Νῶε εἰς τὴν κιβωτόν, καὶ ἦλθεν ὁ κατακλυσμὸς καὶ ἀπώλεσεν ἅπαντας.', 'ēsthion, epinon, egamoun, egamizonto, achri hēs hēmeras eisēlthen Nōe eis tēn kibōton, kai ēlthen ho kataklUsmos kai apōlesen hapantas.', 'The four imperfect verbs — were eating, were drinking, were marrying, were being given in marriage — describe habitual, continuous, ordinary activity. The aorist "the flood came" (ēlthen ho kataklUsmos) marks the sudden rupture of the ordinary. "And destroyed them all" (apōlesen hapantas — utterly destroyed all) — the comprehensive judgment. The key point: there was no progressive series of warnings that would have allowed those not in the ark to prepare at the last moment. Noah entered the ark; the door closed; the flood came.', NULL),
  (28, 'Likewise also as it was in the days of Lot; they did eat, they drank, they bought, they sold, they planted, they builded;', 'ὁμοίως καθὼς ἐγένετο ἐν ταῖς ἡμέραις Λώτ· ἤσθιον, ἔπινον, ἠγόραζον, ἐπώλουν, ἐφύτευον, ᾠκοδόμουν·', 'homoiōs kathōs egeneto en tais hēmerais Lōt; ēsthion, epinon, ēgorazon, epōloun, ephuteuon, ōkodOmoun;', 'The Lot typology (Gen 18-19) expands the picture of normal life: six activities — eating, drinking, buying, selling, planting, building — a comprehensive economic picture of a thriving city. Sodom was prosperous and commercially active right up to the moment of its destruction. The list of activities is longer than Noah''s list, emphasizing the greater apparent normalcy and stability of Sodom on the eve of its judgment. Prosperity can be a lull that blinds to approaching catastrophe.', NULL),
  (29, 'But the same day that Lot went out of Sodom it rained fire and brimstone from heaven, and destroyed them all.', 'ᾗ δὲ ἡμέρᾳ ἐξῆλθεν Λὼτ ἀπὸ Σοδόμων, ἔβρεξεν πῦρ καὶ θεῖον ἀπ'' οὐρανοῦ, καὶ ἀπώλεσεν ἅπαντας.', 'hē de hēmera exēlthen Lōt apo Sodomōn, ebrexen pur kai theion ap'' ouranou, kai apōlesen hapantas.', '"The same day" (hē de hēmera) — the day of Lot''s departure is the day of Sodom''s destruction; the two events are simultaneous. "Fire and brimstone from heaven" (pur kai theion ap'' ouranou — the divine judgment of Genesis 19:24) — a supernatural catastrophe with no natural analog. "Destroyed them all" (apōlesen hapantas) — again complete destruction. The pattern repeats: removal of the righteous remnant coincides precisely with the onset of judgment on those who remain.', NULL),
  (30, 'Even thus shall it be in the day when the Son of man is revealed.', 'κατὰ τὰ αὐτὰ ἔσται ᾗ ἡμέρᾳ ὁ Υἱὸς τοῦ ἀνθρώπου ἀποκαλύπτεται.', 'kata ta auta estai hē hēmera ho Huios tou anthrōpou apokaluptetai.', '"Even thus shall it be" (kata ta auta estai — it will be exactly like this) — the Noah and Lot typologies are not mere illustrations but structural templates for the parousia. "When the Son of man is revealed" (apokaluptetai — is unveiled, apocalypsed; the theological word for the eschatological disclosure) — the revelation of the Son of Man will share the suddenness, the ordinariness of surrounding life, and the comprehensive judgment of both Flood and Sodom. No gradual warning; no transition period; no last-minute escape for the unprepared.', NULL),
  (31, 'In that day, he which shall be upon the housetop, and his stuff in the house, let him not come down to take it away: and he that is in the field, let him likewise not return back.', 'ἐν ἐκείνῃ τῇ ἡμέρᾳ ὃς ἔσται ἐπὶ τοῦ δώματος καὶ τὰ σκεύη αὐτοῦ ἐν τῇ οἰκίᾳ, μὴ καταβάτω ἆραι αὐτά, καὶ ὁ ἐν ἀγρῷ ὁμοίως μὴ ἐπιστρεψάτω εἰς τὰ ὀπίσω.', 'en ekeinē tē hēmera hos estai epi tou dōmatos kai ta skeuē autou en tē oikia, mē katabatō arai auta, kai ho en agrō homoiōs mē epistrepsatō eis ta opisō.', '"In that day" — referring primarily to AD 70''s fall of Jerusalem but also typologically to the final parousia. "Upon the housetop" — the flat Palestinian roof used for storage and leisure. "Let him not come down to take it away" — no time for the collection of possessions. The flight must be immediate. The principle: at the moment of crisis, no material possession is worth the time required to retrieve it. Attachment to things in the moment of eschatological urgency is spiritually fatal.', NULL),
  (32, 'Remember Lot''s wife.', 'μνημονεύετε τῆς γυναικὸς Λώτ.', 'mnēmoneuete tēs gunaikos Lōt.', 'The shortest command in the Gospels — three words in Greek — yet among the most charged. Lot''s wife "looked back" (Gen 19:26) when fleeing Sodom and became a pillar of salt. The backward glance cost her life. The warning is not about nostalgia but about divided allegiance at the moment of decisive departure: turning back toward what is being left behind (the old life, earthly attachments) when the moment demands complete forward movement. "Remember" (mnēmoneuete — keep remembering, present imperative) — this is a standing order for disciples throughout the age.', NULL),
  (33, 'Whosoever shall seek to save his life shall lose it; and whosoever shall lose his life shall preserve it.', 'ὃς ἐὰν ζητήσῃ τὴν ψυχὴν αὐτοῦ σῶσαι, ἀπολέσει αὐτήν, καὶ ὃς ἂν ἀπολέσει, ζῳογονήσει αὐτήν.', 'hos ean zētēsē tēn psuchēn autou sōsai, apOlEsei autēn, kai hos an apolEsei, zōogonēsei autēn.', '"Seek to save his life" (zētēsē tēn psuchēn autou sōsai — who tries to preserve his own soul/life) "shall lose it" (apOlEsei — will destroy it). The paradox is repeated elsewhere (9:24; Matt 10:39; 16:25; Mark 8:35; John 12:25). In the context of the parousia: clinging to present life at the cost of kingdom allegiance results in ultimate loss. "Preserve it" (zōogonēsei — will give it life, will preserve it alive; the same word used of preserving animals alive, Gen 6:19 LXX) — the life lost for Jesus is the life truly found.', NULL),
  (34, 'I tell you, in that night there shall be two men in one bed; the one shall be taken, and the other shall be left.', 'λέγω ὑμῖν, ταύτῃ τῇ νυκτὶ ἔσονται δύο ἐπὶ κλίνης μιᾶς, ὁ εἷς παραλημφθήσεται καὶ ὁ ἕτερος ἀφεθήσεται.', 'legō humin, tautē tē nukti esontai duo epi klinēs mias, ho heis paralēmphthēsetai kai ho heteros aphethēsetai.', '"In that night" — the parousia will occur across different time zones simultaneously (some in bed at night, v.34; some grinding at daytime, v.35). "Shall be taken" (paralēmphthēsetai — will be taken alongside, received) — the taken one is received into blessing (cf. 9:28 where Jesus "takes" the three to the transfiguration); "left" (aphEthēsetai — will be left behind, released) — left to judgment. The intimacy of the pairs (same bed, same millstone) emphasizes that the division is not social or geographic but spiritual.', NULL),
  (35, 'Two women shall be grinding together; the one shall be taken, and the other left.', 'ἔσονται δύο ἀλήθουσαι ἐπὶ τὸ αὐτό, ἡ μία παραλημφθήσεται καὶ ἡ ἑτέρα ἀφεθήσεται.', 'esontai duo alēthousai epi to auto, hē mia paralēmphthēsetai kai hē hetera aphEthēsetai.', 'Women grinding grain together (alēthousai — present participle: grinding, the standard morning domestic activity) in the same physical location doing the same work will be divided. The selection is not by skill, activity, or social proximity but by the invisible reality of faith and allegiance. The pairing of bed (night) and grinding mill (morning activity) covers both the nocturnal and diurnal hours, indicating simultaneity across the globe. The same principle applies across every common context of shared human activity.', NULL),
  (36, 'Two men shall be in the field; the one shall be taken, and the other left.', 'δύο ἔσονται ἐν τῷ ἀγρῷ, ὁ εἷς παραλημφθήσεται καὶ ὁ ἕτερος ἀφεθήσεται.', 'duo esontai en tō agrō, ho heis paralēmphthēsetai kai ho heteros aphEthēsetai.', 'Present in the Textus Receptus and KJV, this verse extends the series of paired separations from the domestic (bed, grinding mill) to the agricultural field. Two men engaged in identical outdoor labour will be sundered at the parousia by the invisible criterion of allegiance to the Son of Man. "Shall be taken" (paralēmphthēsetai — received, taken alongside) and "left" (aphEthēsetai — released, left behind) — the same verbs as vv.34-35, reinforcing the irrevocable and instantaneous nature of the separation. No common occupation, location, or shared experience shields against the coming division.', NULL),
  (37, 'And they answered and said unto him, Where, Lord? And he said unto them, Wheresoever the body is, thither will the eagles be gathered together.', 'καὶ ἀποκριθέντες λέγουσιν αὐτῷ, Ποῦ, Κύριε; ὁ δὲ εἶπεν αὐτοῖς, Ὅπου τὸ σῶμα, ἐκεῖ καὶ οἱ ἀετοὶ ἐπισυναχθήσονται.', 'kai apokrithentes legousin autō, Pou, Kurie; ho de eipen autois, Hopou to sōma, ekei kai hoi aetoi episunachthēsontai.', '"Where, Lord?" (Pou, Kurie) — the disciples ask about the location of the taking. Jesus refuses to give a map and instead gives a proverb: "where the body is, there the eagles will be gathered." Eagles (or vultures — aetoi can mean either) gather instinctively where the carcass is. Applied: when the Son of Man appears, his people will be drawn to him as naturally and inevitably as carrion birds to a carcass. The "where" of the parousia cannot be predetermined; it will be as self-evident as vultures over a carcass — unmistakable to all.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 17;
